VALUES
  ('real-estate-moex-01802', 'real-estate', 'real-estate-moex-102-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '下列何者非不動產說明書不得記載事項之內容？', '["附屬建物除陽台外，其餘項目不得計入買賣價格", "不得為其他違反法律強制或禁止規定之約定", "不得使用未經明確定義之「使用面積」、「受益面積」、「銷售面積」等名詞", "預售屋出售標的，不得記載未經依法領有建造執照之夾層設計或夾層空間面積"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "b925db0a464b", "answer_pdf_sha1": "a82b7a0d612f", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "不動產經紀相關法規概要", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01803', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '湯顯祖《牡丹亭．驚夢》：「原來姹紫嫣紅開遍，似這般都付與斷井頹垣。良辰美 景奈何天，賞心樂事誰家院！」主要表達何種感觸？', '["人生苦短，及時行樂", "韶光易逝，好景不常", "野火燒不盡，春風吹又生", "隨意春芳歇，王孫自可留"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01804', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '趙襄子攻翟，勝老人、中人，使使者來謁之，襄子方食摶飯，有憂色。左右曰： 「一朝而兩城下，此人之所以喜也，今君有憂色何？」襄子曰：「江河之大也，不 過三日；飄風暴雨，日中不須臾。今趙氏之德行，無所於積，一朝而兩城下，亡其 及我乎？」孔子聞之曰：「趙氏其昌乎！」（《呂氏春秋．慎大覽》）這則故事可 說明孔子以為成功的原因，就在於：', '["憂患意識", "乘勝追擊", "同甘共苦", "任勞任怨"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01805', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '「楚莊王好細腰，故朝有餓人。」（《荀子．君道》） 下列選項中，何者最能說明這兩句話的文義？', '["望風披靡", "前倨後恭", "上行下效", "假公濟私 60210 那天，我和父親在江蘇家鄉的河邊上散步，我們恰巧看到一群鴨子，正要下水嬉 戲，我發現河水被牠們弄皺了，感到非常有趣。不久，鴨子又繼續游向對岸。父親問 我：「孩子！你看到了吧？每隻鴨子在水面上，都游出一條屬於自己的水路。」我說： 「我看到了！」父親摸摸我的頭，微笑地說：「你看河裡，大鴨子游出來的水路，是 大路；小鴨子游出來的水路，是小路。每隻鴨子都有自己的路，而且小鴨子也能夠像 大鴨子一樣，從河的此岸到達河的彼岸。」 父親深深地吸口氣，遙望著對岸的鴨子，拍拍我的肩膀：「孩子啊！你也十來歲 了！每一個人都有他自己能夠走的路，如果你的力量很大，能夠走出大路，你也不要 覺得了不起，因為你也只是走一條路而已，當你到達河的彼岸，別人也能夠到達那邊。 如果你的力量很小，你也不要難過，不必羨慕別人的大路，不必認為自己沒有用，因為 你也能夠到達彼岸。」（聖嚴法師〈大鴨游出大路，小鴨游出小路〉）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01806', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '上文中，「每隻鴨子都有自己的路，而且小鴨子也能夠像大鴨子一樣，從河的此岸 到達河的彼岸。」所說的意思，下列選項何者最為貼近？', '["天生我材必有用", "醜小鴨終成天鵝", "塞翁失馬，焉知非福", "知己知彼，百戰百勝"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01807', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '根據上文，作者的父親認為力量很大時走出的大路與力量小時走出的小路，二者之 間真正的差異在於：', '["力量小者若跟隨力量大者的水路，亦可以快速到達河的彼岸", "力量大者須謙虛看待自己的成就，而力量小者則須對自己有信心，不怨天尤人", "所謂能者多勞，力量大者必須加倍付出心力，力量小者盡力即可，不能則止", "大路與小路的差別在於是否努力不懈、堅持到底，若半途而廢，大路亦不可得"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01808', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '子曰：「羣居終日，言不及義，好行小慧，難矣哉！」（《論語．衛靈公》）下列 敘述，何者最能貼切說明上文中「好行小慧」的意義？', '["矯飾善行博取美好名聲", "喜歡運用私智僥倖行事", "不擇手段追求短暫利益", "專門結黨營私圖利個人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01809', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '居是官者，當志其大，捨其細，先其急，後其緩，專利國家而不為身謀。彼汲汲於 名者，猶汲汲於利也。（司馬光〈諫院題名記〉）以下何者不屬於司馬光主張之諫 官應有品德？', '["不務苛細", "先辦急事", "急於求名", "不求私利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01810', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '東昌卞氏，業牛醫者，有女小字臙脂，才姿惠麗。父寶愛之，欲占鳳於清門，而世 族鄙其寒賤，不屑締盟，以故及笄未字。對戶龔姓之妻王氏，佻脫善謔，女閨中談 友也。一日，送至門，見一少年過，白服裙帽，丰采甚都。女意似動，秋波縈轉之。 少年俯其首，趨而去。去既遠，女猶凝眺。王窺其意，戲之曰：「以娘子才貌，得 配若人，庶可無恨。」女暈紅上頰，脈脈不作一語。（蒲松齡〈臙脂〉）根據上文， 下列敘述何者錯誤？', '["女方出身寒門", "男方不解風情", "女方情竇初開", "王氏積極媒合 60210"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01811', 'real-estate', 'real-estate-moex-102-9a386a01', 'sub-real-estate-06', NULL, 'single_choice', '《世說新語．巧藝篇》曰：「顧長康畫人，或數年不點目精。人問其故，顧曰： 『四體妍蚩，本無關於妙處，傳神寫照，正在阿堵中。』」可知顧長康畫人首重：', '["形似", "妍蚩", "傳神", "色彩"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:10+00:00", "source_pdf_sha1": "d22f9357c134", "answer_pdf_sha1": "5bbb7ca18052", "source_family": "moex-gov-tw", "moex": {"exam_code": "102180", "c": "601", "s": "1105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文（作文與測驗）", "year": "102", "exam_name": "102年專技高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
